import xml.etree.ElementTree as ET

def validate_xml(xml_file):
    tree = ET.parse(xml_file)
    root = tree.getroot()
    
    # Validate the XML document by checking its schema
    schema = root.attrib['schema']
    if schema not in ['product', 'customer']:
        raise ValueError('Invalid schema')
    
    # Check for required elements and attributes
    required_elements = ['name', 'price']
    required_attributes = {'name': 'string', 'price': 'float'}
    for element in root.iterfind('.//*'):
        if element.tag not in required_elements:
            raise ValueError('Missing required element')
        for attribute, value in required_attributes.items():
            if attribute not in element.attrib or type(element.attrib[attribute]) != value:
                raise ValueError('Invalid attribute value')
    
    # Check for invalid characters in the XML document
    if any(c not in 'abcdefghijklmnopqrstuvwxyz' for c in root.text):
        raise ValueError('Invalid character in text content')

    return True